-- V1: baseline schema for Gradox2.

create table audit_records (actor_id bigint not null, id bigint generated by default as identity, target_id bigint, timestamp timestamp(6) with time zone, action_type varchar(255) check (action_type in ('UPLOAD','DELETE','VETO','POLICY_CHANGE','PROMOTION','EXPULSION')), details varchar(255), target_entity varchar(255), primary key (id));
create table badges (id bigint generated by default as identity, description varchar(255), name varchar(255) not null, icon oid, primary key (id));
create table courses (id bigint generated by default as identity, code varchar(255) not null unique, name varchar(255) not null, primary key (id));
create table delegations (delegated_at timestamp(6) with time zone, delegatee_id bigint not null, delegator_id bigint not null, id bigint generated by default as identity, primary key (id));
create table file_proposal (file_id bigint, id bigint not null, temp_file_id bigint unique, primary key (id));
create table files (anonymous boolean not null, score float(53), id bigint generated by default as identity, subject_id bigint not null, upload_at timestamp(6) with time zone, uploader_id bigint not null, description varchar(255), file_hash varchar(255), title varchar(255), type varchar(255) check (type in ('APUNTES','EXAMEN','EJERCICIO','OTRO')), file_data oid not null, visibility_level varchar(20) not null default 'PUBLIC', primary key (id));
create table notifications (read boolean not null, id bigint generated by default as identity, recipient_id bigint not null, sent_at timestamp(6) with time zone, link varchar(255), message varchar(255), primary key (id));
create table password_reset_token (expiry_date timestamp(6) not null, id bigint generated by default as identity, user_id bigint not null unique, token varchar(255) not null unique, primary key (id));
create table promotion_proposal (candidate_id bigint not null, id bigint not null, primary key (id));
create table proposals (approval_threshold float(53) not null, quorum_required integer not null, closed_at timestamp(6) with time zone, created_at timestamp(6) with time zone, ends_at timestamp(6) with time zone, id bigint generated by default as identity, proposer_id bigint not null, proposal_type varchar(31) not null, version bigint default 0 not null, action_type varchar(255) not null check (action_type in ('UPLOAD','DELETE','VETO','POLICY_CHANGE','PROMOTION','EXPULSION')), status varchar(255) not null check (status in ('PENDING','APPROVED','REJECTED')), primary key (id));
create table refresh_tokens (revoked boolean not null, expiry_date timestamp(6) not null, id bigint generated by default as identity, user_id bigint not null, token varchar(255) not null unique, primary key (id));
create table scores (score float(53), file_id bigint not null, id bigint generated by default as identity, scored_at timestamp(6) with time zone, voter_id bigint not null, primary key (id));
create table subjects (course_id bigint not null, id bigint generated by default as identity, code varchar(255) not null unique, name varchar(255) not null, primary key (id));
create table temp_files (anonymous boolean not null, id bigint generated by default as identity, subject_id bigint not null, upload_at timestamp(6) with time zone, uploader_id bigint not null, description varchar(255), file_hash varchar(255), title varchar(255), type varchar(255) check (type in ('APUNTES','EXAMEN','EJERCICIO','OTRO')), file_data oid not null, visibility_level varchar(20) not null default 'PUBLIC', primary key (id));
create table user_badges (badge_id bigint not null, user_id bigint not null, primary key (badge_id, user_id));
create table users (enabled boolean not null, reputation float(53) not null, created_at timestamp(6) with time zone not null, id bigint generated by default as identity, last_login timestamp(6) with time zone, email varchar(255) not null unique, password_hash varchar(255) not null, role varchar(255) not null check (role in ('GUEST','USER','MASTER')), username varchar(255) not null unique, profile_picture oid, primary key (id));
create table verification_token (expiry_date timestamp(6), id bigint generated by default as identity, user_id bigint not null unique, token varchar(255), primary key (id));
create table vote_config (approval_threshold float(53) not null, max_pending_uploads integer not null, quorum_required integer not null, id bigint generated by default as identity, primary key (id));
create table votes (in_favor boolean, weight float(53) default 1.0, id bigint generated by default as identity, proposal_id bigint not null, voted_at timestamp(6) with time zone, voter_id bigint not null, primary key (id));
